// ============================================================
// Export Bundler — ZIP creation & download
// ============================================================

import JSZip from 'jszip';
import { generateAllFormats } from './generator.js';

export async function downloadBundle(state, entConfig = {}) {
  const zip = new JSZip();
  const formats = generateAllFormats(state, entConfig);
  const agentName = state.agents[0]?.name?.replace(/\s+/g, '-').toLowerCase() || 'agent';

  // Add all config files
  Object.entries(formats).forEach(([filename, content]) => {
    zip.file(filename, content);
  });

  // Add CLI wrapper scripts
  zip.file('install.sh', generateBashInstaller(agentName));
  zip.file('install.ps1', generatePowerShellInstaller(agentName));

  // Generate ZIP
  const blob = await zip.generateAsync({
    type: 'blob',
    compression: 'DEFLATE',
    compressionOptions: { level: 9 },
  });

  // Trigger download with dispense animation
  triggerDispenseAnimation();

  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${agentName}-agent-bundle.zip`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function generateBashInstaller(name) {
  return `#!/bin/bash
# ${name} Agent — Installer
# Generated by AgentVendi 🎰

echo "🎰 Installing ${name} agent..."

TARGET_DIR="\${1:-.}"

# Detect IDE and copy appropriate config
if [ -d ".cursor" ] || command -v cursor &>/dev/null; then
  cp .cursorrules "$TARGET_DIR/.cursorrules"
  echo "✅ Installed .cursorrules for Cursor"
fi

if command -v windsurf &>/dev/null; then
  cp .windsurfrules "$TARGET_DIR/.windsurfrules"
  echo "✅ Installed .windsurfrules for Windsurf"
fi

if [ -d ".github" ] || command -v gh &>/dev/null; then
  mkdir -p "$TARGET_DIR/.github"
  cp copilot-instructions.md "$TARGET_DIR/.github/copilot-instructions.md"
  echo "✅ Installed copilot-instructions.md for GitHub Copilot"
fi

if command -v claude &>/dev/null; then
  cp CLAUDE.md "$TARGET_DIR/CLAUDE.md"
  echo "✅ Installed CLAUDE.md for Claude Code"
fi

if command -v aider &>/dev/null; then
  cp .aider.conf.yml "$TARGET_DIR/.aider.conf.yml"
  echo "✅ Installed .aider.conf.yml for Aider"
fi

cp .clinerules "$TARGET_DIR/.clinerules" 2>/dev/null
cp agent.json "$TARGET_DIR/agent.json"

echo ""
echo "🎉 ${name} agent installed successfully!"
echo "📝 See AGENT_README.md for details."
`;
}

function generatePowerShellInstaller(name) {
  return `# ${name} Agent — Installer
# Generated by AgentVendi 🎰

param([string]$TargetDir = ".")

Write-Host "🎰 Installing ${name} agent..." -ForegroundColor Cyan

Copy-Item ".cursorrules" -Destination "$TargetDir\\.cursorrules" -ErrorAction SilentlyContinue
Copy-Item ".windsurfrules" -Destination "$TargetDir\\.windsurfrules" -ErrorAction SilentlyContinue
Copy-Item "CLAUDE.md" -Destination "$TargetDir\\CLAUDE.md" -ErrorAction SilentlyContinue
Copy-Item ".clinerules" -Destination "$TargetDir\\.clinerules" -ErrorAction SilentlyContinue
Copy-Item "agent.json" -Destination "$TargetDir\\agent.json" -ErrorAction SilentlyContinue

$githubDir = Join-Path $TargetDir ".github"
if (!(Test-Path $githubDir)) { New-Item -ItemType Directory -Path $githubDir -Force | Out-Null }
Copy-Item "copilot-instructions.md" -Destination "$githubDir\\copilot-instructions.md" -ErrorAction SilentlyContinue

Write-Host ""
Write-Host "🎉 ${name} agent installed successfully!" -ForegroundColor Green
Write-Host "📝 See AGENT_README.md for details."
`;
}

function triggerDispenseAnimation() {
  const machine = document.querySelector('.vending-machine');
  if (machine) {
    machine.style.animation = 'none';
    machine.offsetHeight;
    machine.classList.add('dispensing');

    // Add a temporary dispense visual
    const overlay = document.createElement('div');
    overlay.style.cssText = `
      position: fixed; top: 0; left: 0; width: 100vw; height: 100vh;
      background: radial-gradient(ellipse at center, rgba(57,255,20,0.15) 0%, transparent 70%);
      pointer-events: none; z-index: 999;
      animation: dispenseDrop 0.8s ease forwards;
    `;
    document.body.appendChild(overlay);
    setTimeout(() => {
      overlay.remove();
      machine.classList.remove('dispensing');
    }, 1200);
  }
}
